#!/usr/bin/env bun
'use strict';

const { spawnSync } = require('node:child_process');
const { join } = require('node:path');

const bunExecutable = process.env.BUN || 'bun';
const result = spawnSync(
  bunExecutable,
  [join(__dirname, '..', 'dist', 'cli.js'), ...process.argv.slice(2)],
  { stdio: 'inherit' }
);

if (result.error) {
  if (result.error.code === 'ENOENT') {
    console.error('sshx requires Bun >= 1.3 on PATH. Install Bun from https://bun.sh');
    process.exit(1);
  }
  throw result.error;
}

process.exit(result.status ?? 1);

